# == User Data Persistence ==
@app.get("/userdata")
async def get_userdata(key: str = None, x_token: str = Header(None)):
    auth = resolve_auth(x_token)
    if not sb:
        raise HTTPException(status_code=503, detail="DB unavailable")
    try:
        if auth["kind"] == "invite":
            q = sb.table("user_data").select("key,value").eq("token", auth["token"])
        else:
            q = sb.table("user_data").select("key,value").eq("user_id", auth["user_id"])
        if key:
            q = q.eq("key", key)
        res = q.execute()
        if key:
            row = next((r for r in (res.data or []) if r["key"] == key), None)
            return {"value": row["value"] if row else None}
        return {"data": {r["key"]: r["value"] for r in (res.data or [])}}
    except Exception as e:
        raise HTTPException(status_code=500, detail=str(e))

@app.post("/userdata")
async def set_userdata(body: dict, x_token: str = Header(None)):
    auth = resolve_auth(x_token)
    if not sb:
        raise HTTPException(status_code=503, detail="DB unavailable")
    key = body.get("key")
    value = body.get("value")
    if not key:
        raise HTTPException(status_code=400, detail="key required")
    try:
        import datetime as _dt
        updated_at = _dt.datetime.utcnow().isoformat()
        if auth["kind"] == "invite":
            sb.table("user_data").upsert(
                {"token": auth["token"], "key": key, "value": value, "updated_at": updated_at},
                on_conflict="token,key",
            ).execute()
        else:
            existing = sb.table("user_data").select("key").eq("user_id", auth["user_id"]).eq("key", key).execute()
            payload = {"user_id": auth["user_id"], "key": key, "value": value, "updated_at": updated_at}
            if existing.data:
                sb.table("user_data").update({"value": value, "updated_at": updated_at}).eq("user_id", auth["user_id"]).eq("key", key).execute()
            else:
                sb.table("user_data").insert(payload).execute()
        return {"ok": True}
    except Exception as e:
        raise HTTPException(status_code=500, detail=str(e))

